# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharehandler

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import android.widget.Toast

class ShareReceiverActivity : Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleShareIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        handleShareIntent(intent)
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> handleSingleShare(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleMultipleShare(intent)
            else -> finish()
        }
    }

    private fun handleSingleShare(intent: Intent) {
        when {
            intent.type?.startsWith("text/") == true -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)
                processSharedUrlOrText(sharedText, sharedSubject)
            }

            intent.type?.startsWith("image/") == true -> {
                val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
                processSharedImage(imageUri)
            }

            else -> {
                Toast.makeText(this, "Unsupported shared content", Toast.LENGTH_SHORT).show()
            }
        }
        finish()
    }

    private fun handleMultipleShare(intent: Intent) {
        val uris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (uris.isNullOrEmpty()) {
            Toast.makeText(this, "No shared items found", Toast.LENGTH_SHORT).show()
        } else {
            processSharedImages(uris)
        }
        finish()
    }

    private fun processSharedUrlOrText(sharedText: String?, subject: String?) {
        if (sharedText.isNullOrBlank()) {
            Toast.makeText(this, "No text shared", Toast.LENGTH_SHORT).show()
            return
        }

        val extractedUrl = extractUrl(sharedText)
        if (extractedUrl != null) {
            Log.d(TAG, "Shared URL: $extractedUrl")
            Toast.makeText(this, "Received URL: $extractedUrl", Toast.LENGTH_SHORT).show()
        } else {
            Log.d(TAG, "Shared text: $sharedText, subject: $subject")
            Toast.makeText(this, "Received text", Toast.LENGTH_SHORT).show()
        }
    }

    private fun processSharedImage(imageUri: Uri?) {
        if (imageUri == null) {
            Toast.makeText(this, "No image shared", Toast.LENGTH_SHORT).show()
            return
        }

        Log.d(TAG, "Shared image URI: $imageUri")
        Toast.makeText(this, "Received image", Toast.LENGTH_SHORT).show()
    }

    private fun processSharedImages(imageUris: List<Uri>) {
        Log.d(TAG, "Shared ${imageUris.size} images")
        Toast.makeText(this, "Received ${imageUris.size} images", Toast.LENGTH_SHORT).show()
    }

    private fun extractUrl(text: String): String? {
        val urlRegex = Regex("(https?://\\S+)")
        return urlRegex.find(text)?.value?.trimEnd('.', ',', ';', ')', ']')
    }

    companion object {
        private const val TAG = "ShareReceiverActivity"
    }
}

<manifest xmlns:android="http://schemas.android.com/apk/res/android"
    package="com.example.sharehandler">

    <application>

        <activity
            android:name=".ShareReceiverActivity"
            android:exported="true"
            android:theme="@android:style/Theme.Translucent.NoTitleBar">
            <intent-filter>
                <action android:name="android.intent.action.SEND" />
                <category android:name="android.intent.category.DEFAULT" />
                <data android:mimeType="text/*" />
                <data android:mimeType="image/*" />
            </intent-filter>

            <intent-filter>
                <action android:name="android.intent.action.SEND_MULTIPLE" />
                <category android:name="android.intent.category.DEFAULT" />
                <data android:mimeType="image/*" />
            </intent-filter>
        </activity>

    </application>
</manifest>